<template><div class="page"><div class="page-head"><div><h2>参与主体与账号审核</h2><p>系统管理员负责核验主体资质、审核注册申请并管理账号状态。</p></div></div><el-table :data="list" border><el-table-column prop="username" label="账号" /><el-table-column prop="display_name" label="负责人" /><el-table-column prop="role" label="申请角色" /><el-table-column prop="organization" label="单位名称" /><el-table-column prop="phone" label="联系电话" /><el-table-column label="状态"><template slot-scope="{row}"><el-tag :type="type(row.status)">{{ name(row.status) }}</el-tag></template></el-table-column><el-table-column label="管理操作" width="280"><template slot-scope="{row}"><template v-if="row.role!=='系统管理员'"><el-button v-if="row.status==='pending'||row.status==='rejected'" size="mini" type="success" @click="change(row,'approved')">审核通过</el-button><el-button v-if="row.status==='pending'" size="mini" type="danger" @click="change(row,'rejected')">拒绝申请</el-button><el-button v-if="row.status==='approved'" size="mini" type="warning" @click="change(row,'disabled')">禁用账号</el-button><el-button v-if="row.status==='disabled'" size="mini" type="success" @click="change(row,'approved')">恢复账号</el-button></template><span v-else>唯一系统管理员</span></template></el-table-column></el-table></div></template>
<script>import { getUsers, updateUserStatus } from '@/api/user'; export default { data: () => ({ list: [] }), created() { this.load() }, methods: { load() { getUsers().then(r => { this.list = r.data }) }, name(s) { return ({ pending: '待审核', approved: '正常', rejected: '审核拒绝', disabled: '已禁用' })[s] }, type(s) { return ({ pending: 'warning', approved: 'success', rejected: 'danger', disabled: 'info' })[s] }, change(r, s) { this.$prompt('请输入审核或管理备注', '账号状态管理', { inputValue: s === 'approved' ? '主体资质核验通过' : '' }).then(x => updateUserStatus({ id: r.id, status: s, note: x.value })).then(x => { this.$message.success(x.message); this.load() }) } }}</script>
